SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpb_receipt_loan_clear (AS_CONNO CHAR , AS_METHOD CHAR) RETURNS bigint AS $body$
DECLARE

  ldc_amount bigint;

BEGIN

if as_method = 'P' then
    SELECT sum(SC_COM_M_RECEIPT_ITEM.PRINCIPAL_AMOUNT)
    into STRICT	ldc_amount
    FROM SC_COM_M_RECEIPT,
         SC_COM_M_RECEIPT_ITEM
   WHERE ( SC_COM_M_RECEIPT.RECEIPT_NO = SC_COM_M_RECEIPT_ITEM.RECEIPT_NO ) and
         ( ( sc_com_m_receipt.loan_contract_no = AS_CONNO ) AND ( sc_com_m_receipt.money_type_id = 'CLR' ) AND ( sc_com_m_receipt.receipt_status = '0' ) AND ( sc_com_m_receipt_item.principal_amount > 0 ) )
;

else
    SELECT sum(SC_COM_M_RECEIPT_ITEM.INTEREST_AMOUNT)
    into STRICT	ldc_amount
    FROM SC_COM_M_RECEIPT,
         SC_COM_M_RECEIPT_ITEM
   WHERE ( SC_COM_M_RECEIPT.RECEIPT_NO = SC_COM_M_RECEIPT_ITEM.RECEIPT_NO ) and
         ( ( sc_com_m_receipt.loan_contract_no = AS_CONNO ) AND ( sc_com_m_receipt.money_type_id = 'CLR' ) AND ( sc_com_m_receipt.receipt_status = '0' ) AND ( sc_com_m_receipt_item.interest_amount > 0 ) )
;

end if;

return nvn(ldc_amount);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON FUNCTION fpb_receipt_loan_clear (AS_CONNO CHAR , AS_METHOD CHAR) FROM PUBLIC;

